import java.io.IOException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSSafeServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Properly encoding and escaping user input before printing it back to the response
        Encoder encoder = ESAPI.encoder();

        response.setContentType("text/html");
        response.setCharacterEncoding("UTF-8");

        String safeUserInput = encoder.encodeForHTML(userInput);

        response.getWriter().println("<html>");
        response.getWriter().println("<body>");
        response.getWriter().println("<p>User input: " + safeUserInput + "</p>");
        response.getWriter().println("</body>");
        response.getWriter().println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
